Here's the XAML and ViewModel setup:

## XAML

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="Auto,*">
                        <Image Source="{Binding Icon}"
                               WidthRequest="40" HeightRequest="40" />
                        <Label Grid.Column="1"
                               Text="{Binding Name}"
                               VerticalOptions="Center"
                               Margin="12,0,0,0" />
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
            <CollectionView.EmptyView>
                <Label Text="No items found."
                       HorizontalOptions="Center"
                       VerticalOptions="Center" />
            </CollectionView.EmptyView>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

## ViewModel

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IItemService _itemService;

    [ObservableProperty]
    private bool isRefreshing;

    [ObservableProperty]
    private Item? currentItem;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IItemService itemService)
    {
        _itemService = itemService;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        var data = await _itemService.GetItemsAsync();
        Items.Clear();
        foreach (var item in data)
            Items.Add(item);

        IsRefreshing = false; // signals RefreshView to stop the spinner
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        await Shell.Current.GoToAsync($"detail?id={CurrentItem.Id}");

        // Reset selection so the user can re-select the same item later
        CurrentItem = null;
    }
}
```

## Key bindings explained

| XAML property | ViewModel property | Purpose |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool, TwoWay) | Shows/hides spinner; set `false` when done |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-to-refresh |
| `CollectionView.SelectedItem` | `CurrentItem` (TwoWay) | Tracks the selected item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on selection change to navigate |

**Important notes:**
- Use `ObservableCollection<T>` (not `List<T>`) so add/remove updates the UI.
- Set `CurrentItem = null` after navigation so the same item can be tapped again.
- Set `IsRefreshing = false` at the end of your refresh logic to dismiss the spinner.
- Always set `x:DataType` on both the page and the `DataTemplate` for compiled bindings.
